        <div x-show="modal" x-cloak class="fixed inset-0 z-50 overflow-y-auto" role="dialog" aria-modal="true"><div class="flex min-h-full items-end justify-center sm:items-center sm:p-6"><div class="fixed inset-0 bg-ink-950/65 backdrop-blur-sm" @click="close()"></div><form :action="form.action" method="POST" class="relative w-full rounded-t-3xl bg-white shadow-2xl sm:max-w-2xl sm:rounded-3xl">@csrf<template x-if="mode==='edit'"><input type="hidden" name="_method" value="PUT"></template><input type="hidden" name="plan_modal" :value="mode"><input type="hidden" name="plan_id" :value="form.id"><input type="hidden" name="plan_action" :value="form.action"><div class="flex items-start justify-between border-b border-slate-100 px-5 py-5 sm:px-7"><div><p class="text-xs font-bold uppercase tracking-[.18em] text-brand-600" x-text="mode==='edit'?'Atualizar plano':'Novo cadastro'"></p><h2 class="mt-1 text-xl font-black text-ink-950" x-text="mode==='edit'?'Editar plano':'Novo plano'"></h2></div><button type="button" class="grid size-10 place-items-center rounded-xl text-slate-400 hover:bg-slate-100" @click="close()"><x-icon name="close"/></button></div><div class="max-h-[68vh] overflow-y-auto px-5 py-6 sm:px-7">@if($errors->any())<div class="mb-5 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-800">Revise os dados informados.</div>@endif<div class="grid gap-5 sm:grid-cols-2"><div class="sm:col-span-2"><label class="label">Nome do plano</label><input class="field" name="name" x-model="form.name" required x-ref="nameInput"></div><div><label class="label">Valor recorrente</label><input class="field" type="number" min="0.01" step="0.01" name="price" x-model="form.price" required></div><div><label class="label">Taxa de matrícula</label><input class="field" type="number" min="0" step="0.01" name="enrollment_fee" x-model="form.enrollment_fee" required></div><div><label class="label">Periodicidade</label><select class="field" name="billing_interval_months" x-model="form.billing_interval_months"><option value="1">Mensal</option><option value="3">Trimestral</option><option value="6">Semestral</option><option value="12">Anual</option></select></div><div><label class="label">Status</label><select class="field" name="active" x-model="form.active"><option value="1">Ativo</option><option value="0">Inativo</option></select></div><div class="sm:col-span-2"><label class="label">Descrição</label><textarea class="field" name="description" rows="3" x-model="form.description"></textarea></div></div><div x-show="mode==='edit'" class="mt-5 rounded-xl bg-amber-50 px-4 py-3 text-sm text-amber-800">Alterar o valor afeta apenas novas matrículas.</div></div><div class="flex flex-col-reverse gap-3 border-t border-slate-100 px-5 py-4 sm:flex-row sm:justify-end sm:px-7"><button type="button" class="btn-secondary" @click="close()">Cancelar</button><button class="btn-primary" x-text="mode==='edit'?'Salvar alterações':'Salvar plano'"></button></div></form></div></div>
