    <script>function planManager(c){const empty=()=>({id:'',name:'',price:'',enrollment_fee:'0',billing_interval_months:'1',description:'',active:'1',action:c.storeUrl});return{modal:false,mode:'create',form:empty(),init(){if(c.initialMode==='edit'&&c.initialPlan)this.openEdit(c.initialPlan);else if(c.initialMode==='create'){this.mode='create';this.form={...empty(),...(c.initialPlan||{})};this.show()}},openCreate(){this.mode='create';this.form=empty();this.show()},openEdit(x){this.mode='edit';this.form={...empty(),...x,billing_interval_months:String(x.billing_interval_months),active:String(x.active)};this.show()},show(){this.modal=true;document.body.classList.add('overflow-hidden');this.$nextTick(()=>this.$refs.nameInput?.focus())},close(){this.modal=false;document.body.classList.remove('overflow-hidden')}}}</script>
